Langkah #2: Periksa Duplikasi

wvs_data &lt;- wvs_data |&gt; 
  distinct(id_responden, .keep_all = TRUE)

Pivot: Reshape Data

wvs_cleaned |&gt; 
    summarize(
        rata_kepuasan = mean(kepuasan_hidup),
        .by = c(negara, kelompok_usia)
    ) |&gt; 
    pivot_wider(
        names_from = kelompok_usia,
        values_from = rata_kepuasan
    )

