Matriks Korelasi

library(corrplot)

wvs_cleaned |&gt; 
  select(kepuasan_hidup, kepuasan_finansial, religiusitas,
         kebebasan_memilih, usia) |&gt; 
  cor(use = "complete.obs") |&gt; 
  corrplot(method = "color", type = "upper",
           addCoef.col = "black", number.cex = 0.8,
           tl.col = "black", tl.cex = 0.8)

Factor Loadings

parameterEstimates(cfa_fit, standardized = TRUE) |&gt;
  filter(op == "=~") |&gt;
  select(lhs, rhs, est, std.all, pvalue) |&gt;
  kable(digits = 3, col.names = c("Laten", "Indikator",
                                   "Loading", "Std. Loading", "p"))

Interpretasi Hasil

paths &lt;- parameterEstimates(sem_fit, standardized = TRUE) |&gt;
  filter(op == "~") |&gt;
  select(lhs, rhs, std.all, pvalue) |&gt;
  mutate(
    hipotesis = paste0("H", row_number()),
    path = paste(rhs, "-&gt;", lhs),
    kesimpulan = ifelse(pvalue &lt; 0.05 & std.all &gt; 0, "Didukung", "Tidak Didukung")
  )
paths |&gt; select(hipotesis, path, std.all, pvalue, kesimpulan) |&gt;
  kable(digits = 3)

Interpretasi Hipotesis PLS-SEM

boot_paths &lt;- boot_summary$bootstrapped_paths
as.data.frame(boot_paths) |&gt;
  rownames_to_column("Path") |&gt;
  kable(digits = 3)
